def decide(g,m):
    if m["surrogate_scale_top1_guard_weakened"]: return "top1_guard_invariant_violation","D98G_TOP1_GUARD_REPAIR"
    if m["surrogate_scale_D68_preservation_rate"]<1.0: return "d68_regression_detected","D98D_D68_REGRESSION_REPAIR"
    if not m["surrogate_scale_truth_leak_audit_passed"] or not m["surrogate_scale_oracle_isolation_passed"]: return "d98_truth_leak_or_oracle_contamination_detected","D98L_TRUTH_LEAK_REPAIR"
    if not g["sentinel_collapse_passed"] or m["forbidden_feature_detected"]: return "d98_shortcut_memorization_detected","D98H_SHORTCUT_MEMORIZATION_REPAIR"
    if not m["split_integrity_passed"] or m["train_test_ood_contamination_detected"]: return "d98_split_contamination_detected","D98S_SPLIT_INTEGRITY_REPAIR"
    if m["fallback_rows"]>0: return "d98_rust_fallback_detected","D98R_RUST_PATH_REPAIR"
    failed=[k for k,v in g.items() if not v]
    feature_failed=[k for k in failed if k.startswith("feature_noise") or k.startswith("feature_dropout") or k=="feature_corruption_failure_rate"]
    if feature_failed: return "d98_surrogate_feature_robustness_failure","D98F_FEATURE_ROBUSTNESS_REPAIR"
    if "calibration_strict_false_confidence_rate" in failed or "false_positive_confidence_tail_rate" in failed: return "d98_surrogate_calibration_failure","D98C_CALIBRATION_REPAIR"
    if "surrogate_scale_worst_seed_accuracy" in failed or "worst_tail_failure_rate" in failed or "mixed_tail_compound_failure_rate" in failed: return "d98_surrogate_tail_risk_detected","D98T_SURROGATE_TAIL_RISK_REPAIR"
    if failed: return "d98_invalid_metric_or_report_inconsistency","D98_REPORTING_REPAIR"
    return "d98_surrogate_adversarial_scale_confirmed","D99_RECURRENT_ROUTING_MICROCIRCUIT_PROTOTYPE"

