def write_report(out,decision,m,scale):
    lines=[f"# {TASK}","","D98 adversarially scale-confirms SURROGATE_SMALL_MLP_FAIR using D97-approved inference-time non-truth features only.","",f"- decision: `{decision['decision']}`",f"- next: `{decision['next']}`",f"- best fair surrogate: `{m['best_fair_surrogate_arm']}`",f"- test/OOD/stress/min/worst: `{m['surrogate_scale_test_accuracy']}` / `{m['surrogate_scale_ood_accuracy']}` / `{m['surrogate_scale_stress_accuracy']}` / `{m['surrogate_scale_min_seed_accuracy']}` / `{m['surrogate_scale_worst_seed_accuracy']}`",f"- low-cost/OOD/top1 tail score: `{m['surrogate_scale_combined_low_cost_ood_top1_ambiguity_tail_score']}`",f"- stress modes: `{','.join(scale['stress_modes'])}`","","## Boundary","",BOUNDARY,""]
    (out/"report.md").write_text("\n".join(lines),encoding="utf-8")

def main():
    p=argparse.ArgumentParser(); p.add_argument("--out",default=str(DEFAULT_OUT)); p.add_argument("--seeds",default="19001,19002,19003,19004,19005,19006,19007,19008,19009,19010,19011,19012"); p.add_argument("--train-rows-per-seed",type=int,default=540); p.add_argument("--test-rows-per-seed",type=int,default=540); p.add_argument("--ood-rows-per-seed",type=int,default=540); p.add_argument("--stress-seeds",default="19101,19102,19103,19104,19105,19106"); p.add_argument("--stress-rows-per-seed",type=int,default=720); p.add_argument("--workers",default="auto"); p.add_argument("--cpu-target",default="50-75"); p.add_argument("--heartbeat-sec",type=int,default=20); args=p.parse_args(); os.environ.setdefault("OMP_NUM_THREADS","1"); os.environ.setdefault("MKL_NUM_THREADS","1"); os.environ.setdefault("OPENBLAS_NUM_THREADS","1")
    out=Path(args.out); out.mkdir(parents=True,exist_ok=True); write_json(out/"queue.json",{"task":TASK,"created_at":round(time.time(),3),"seeds":parse_seeds(args.seeds),"rows_per_seed":{"train":args.train_rows_per_seed,"test":args.test_rows_per_seed,"ood":args.ood_rows_per_seed},"stress_seeds":parse_seeds(args.stress_seeds),"stress_rows_per_seed":args.stress_rows_per_seed,"stress_modes":STRESS_MODES,"workers":args.workers,"cpu_target":args.cpu_target,"heartbeat_sec":args.heartbeat_sec}); append_jsonl(out/"progress.jsonl",{"time":round(time.time(),3),"phase":"phase0","message":"starting D98 D97 upstream audit"})
    restore=ensure_d97(args); write_json(out/"artifact_restore_report.json",restore); manifest=d97_manifest(restore); write_json(out/"d97_upstream_manifest.json",manifest); append_jsonl(out/"progress.jsonl",{"time":round(time.time(),3),"phase":"run","message":"building D98 adversarial scale reports"}); agg,dec=build_reports(args,out,manifest); append_jsonl(out/"progress.jsonl",{"time":round(time.time(),3),"phase":"complete","decision":dec["decision"]})
    m=agg["metrics"]; print(json.dumps({"task":TASK,"out":str(out),"decision":dec["decision"],"next":dec["next"],"best_fair_surrogate_arm":m["best_fair_surrogate_arm"],"surrogate_scale_test_accuracy":m["surrogate_scale_test_accuracy"],"failed_jobs":m["failed_jobs"]},indent=2))
